import redis
import json
import hashlib

r = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

class CachedMLService:
    def __init__(self, model, cache_ttl: int = 3600):
        self.model = model
        self.cache = r
        self.ttl = cache_ttl

    def _cache_key(self, features: list) -> str:
        feature_str = json.dumps(features, sort_keys=True)
        return f'ml:pred:{hashlib.md5(feature_str.encode()).hexdigest()}'

    def predict(self, features: list) -> dict:
        key = self._cache_key(features)

        # Check cache first
        cached = self.cache.get(key)
        if cached:
            return {'prediction': json.loads(cached), 'source': 'cache'}

        # Model inference
        pred = float(self.model.predict([features])[0])
        prob = float(self.model.predict_proba([features])[0].max())

        result = {'prediction': pred, 'confidence': prob}
        self.cache.setex(key, self.ttl, json.dumps(result))
        return {**result, 'source': 'model'}
